sql:
SELECT component_type_name, description
FROM component_types
WHERE component_type_name = UPPER(component_type_name);

SELECT ui_components.component_id, ui_components.description, component_types.component_type_name
FROM ui_components
INNER JOIN component_types ON ui_components.component_type_id = component_types.component_type_id;

SELECT component_type_name
FROM component_types
WHERE component_type_id = 1 AND component_type_name = 'multiSelector';

external_knowledge:
- 'Top few actions' refers to the first three events in the sequence based on event name;
- 'Parts of the user interface' are components from the `ui_components` table;
- 'Initial activities' are events associated with each component, prioritized by name in ascending order.

sql:
SELECT component_id, description, created_at, updated_at
FROM ui_components
WHERE component_type_id = 1;

SELECT COUNT(DISTINCT ct.component_type_id) 
FROM component_types ct 
INNER JOIN ui_components uc ON ct.component_type_id = uc.component_type_id;

SELECT component_type_name
FROM component_types
WHERE component_type_id = 0;

SELECT COUNT(*) 
FROM component_properties 
WHERE property_name = 'mode';

SELECT component_type_id, COUNT(*)
FROM ui_components
GROUP BY component_type_id;

SELECT description 
FROM ui_components 
WHERE component_id = 0;

SELECT ui.component_id, ui.description
FROM ui_components ui
INNER JOIN component_types ct ON ui.component_type_id = ct.component_type_id;
